const trade = $('Loop Trades').item.json;
const priceData = $('Fetch Current Price').item.json;
const klines = $('Fetch Recent OHLCV for ATR').item.json;

const currentPrice = parseFloat(priceData.price);

// Compute ATR14 from recent klines
const candles = klines.map(c => ({
  high: parseFloat(c[2]),
  low: parseFloat(c[3]),
  close: parseFloat(c[4])
}));

function calcATR(candles, period) {
  const tr = [];
  for (let i = 1; i < candles.length; i++) {
    tr.push(Math.max(
      candles[i].high - candles[i].low,
      Math.abs(candles[i].high - candles[i - 1].close),
      Math.abs(candles[i].low - candles[i - 1].close)
    ));
  }
  let atr = tr.slice(0, period).reduce((a, b) => a + b, 0) / period;
  for (let i = period; i < tr.length; i++) {
    atr = (atr * (period - 1) + tr[i]) / period;
  }
  return atr;
}

const currentAtr14 = candles.length >= 15 ? calcATR(candles, 14) : null;

// Check trailing stop
const entryPrice = parseFloat(trade.entry_price);
const currentStop = parseFloat(trade.current_stop);
const trailAtrMult = parseFloat(trade.trailing_atr_mult);
const trailActivation = parseFloat(trade.trail_activation_pct);

let result = {
  trade_id: trade.id,
  coin: trade.coin,
  direction: trade.direction,
  entry_price: entryPrice,
  current_price: currentPrice,
  current_stop: currentStop,
  position_size_units: parseFloat(trade.position_size_units),
  exchange_order_id: trade.exchange_order_id,
  stop_hit: false,
  stop_updated: false,
  new_stop: currentStop,
  action: 'none'
};

if (trade.direction === 'long') {
  if (currentPrice <= currentStop) {
    result.stop_hit = true;
    result.exit_price = currentStop;
    result.action = 'close';
    return [{ json: result }];
  }
  const newHigh = Math.max(parseFloat(trade.highest_since_entry || entryPrice), currentPrice);
  const profitPct = (currentPrice - entryPrice) / entryPrice;
  if (profitPct >= trailActivation && currentAtr14) {
    const newStop = newHigh - (trailAtrMult * currentAtr14);
    if (newStop > currentStop) {
      result.stop_updated = true;
      result.new_stop = Math.round(newStop * 1e8) / 1e8;
      result.highest_since_entry = newHigh;
      result.action = 'update_stop';
    }
  }
} else if (trade.direction === 'short') {
  if (currentPrice >= currentStop) {
    result.stop_hit = true;
    result.exit_price = currentStop;
    result.action = 'close';
    return [{ json: result }];
  }
  const newLow = Math.min(parseFloat(trade.lowest_since_entry || entryPrice), currentPrice);
  const profitPct = (entryPrice - currentPrice) / entryPrice;
  if (profitPct >= trailActivation && currentAtr14) {
    const newStop = newLow + (trailAtrMult * currentAtr14);
    if (newStop < currentStop) {
      result.stop_updated = true;
      result.new_stop = Math.round(newStop * 1e8) / 1e8;
      result.lowest_since_entry = newLow;
      result.action = 'update_stop';
    }
  }
}

return [{ json: result }];

const d = $input.first().json;
const side = d.direction === 'long' ? 'SELL' : 'BUY';
const timestamp = Date.now();
const qty = Math.floor(d.position_size_units * 1e8) / 1e8;
const queryString = `symbol=${d.coin.replace('/', '')}&side=${side}&type=MARKET&quantity=${qty}&timestamp=${timestamp}`;
const crypto = require('crypto');
const signature = crypto.createHmac('sha256', $env.BINANCE_API_SECRET).update(queryString).digest('hex');
return [{ json: { ...d, queryString, signature } }];

const closeResp = $input.first().json;
const tradeData = $('Build Close Order').first().json;

const fills = closeResp.fills || [];
const totalQty = fills.reduce((s, f) => s + parseFloat(f.qty), 0);
const totalVal = fills.reduce((s, f) => s + parseFloat(f.qty) * parseFloat(f.price), 0);
const exitPrice = totalQty > 0 ? totalVal / totalQty : tradeData.current_price;

const pnlUsdt = tradeData.direction === 'long'
  ? (exitPrice - tradeData.entry_price) * totalQty
  : (tradeData.entry_price - exitPrice) * totalQty;
const pnlPct = pnlUsdt / tradeData.position_size_usdt;
const isWin = pnlUsdt > 0;

return [{ json: { ...tradeData, exitPrice, pnlUsdt, pnlPct, isWin, totalQty } }];
